window.FXEarthGlobe._updateLegendUI = function(containerSelector) {
  var instance = window.FXEarthGlobe._instances[containerSelector];
  if (!instance || !instance.overlayElement) return;
  var settings = instance.settings || {};
  var match = containerSelector.match(/\d+/);
  var slotId = match ? match[0] : '0';
  var legendEl = document.getElementById('sh-radar-legend-' + slotId);
  if (!legendEl) return;

  if (settings.globeShowLegend === false) {
    legendEl.style.display = 'none';
    return;
  }

  var showClouds = !!settings.globeLayerClouds;
  var showPrecip = !!settings.globeLayerPrecipitation;
  var showLightning = !!settings.globeLayerLightning;
  var showVortex = !!settings.globeLayerVortex;
  var showTemp = !!settings.globeLayerTemperature;

  if (!showClouds && !showPrecip && !showLightning && !showVortex && !showTemp) {
    legendEl.style.display = 'none';
    return;
  }

  legendEl.style.display = 'flex';
  
  var html = '';
  if (showClouds) {
    html += '<div class="legend-row"><span><span style="display:inline-block; width:5px; height:5px; background:#f0f8ff; border-radius:50%; margin-right:6px; vertical-align:middle; box-shadow:0 0 3px #f0f8ff;"></span>☁️ CLOUDS [SATELLITE]</span><span style="color: #d1d7e0;">ACTIVE</span></div>';
  }
  if (showPrecip) {
    html += '<div class="legend-row"><span>🌧️ PRECIPITATION</span><span>' +
            '<span style="display:inline-block; width:5px; height:5px; background:#00ff66; border-radius:50%; margin-right:3px; vertical-align:middle;"></span><span style="color: #00ff66; margin-right:6px;">[LOW]</span>' +
            '<span style="display:inline-block; width:5px; height:5px; background:#ffaa00; border-radius:50%; margin-right:3px; vertical-align:middle;"></span><span style="color: #ffaa00; margin-right:6px;">[MED]</span>' +
            '<span style="display:inline-block; width:5px; height:5px; background:#ff3300; border-radius:50%; margin-right:3px; vertical-align:middle;"></span><span style="color: #ff3300;">[HIGH]</span>' +
            '</span></div>';
  }
  if (showLightning) {
    html += '<div class="legend-row"><span><span style="display:inline-block; width:5px; height:5px; background:#00f3ff; border-radius:50%; margin-right:6px; vertical-align:middle; box-shadow:0 0 3px #00f3ff;"></span>⚡ LIGHTNING [DISCHARGE]</span><span style="color: #00f3ff;">ACTIVE</span></div>';
  }
  if (showVortex) {
    html += '<div class="legend-row"><span><span style="display:inline-block; width:5px; height:5px; background:#f0abfc; border-radius:50%; margin-right:6px; vertical-align:middle; box-shadow:0 0 3px #f0abfc;"></span>🌪️ VORTEX [CYCLONE/TORNADO]</span><span style="color: #f0abfc;">ACTIVE</span></div>';
  }
  if (showTemp) {
    html += '<div class="legend-row"><span>🌡️ TEMPERATURE</span><span>' +
            '<span style="display:inline-block; width:5px; height:5px; background:#6366f1; border-radius:50%; margin-right:3px; vertical-align:middle;"></span><span style="color: #6366f1; margin-right:6px;">[COLD]</span>' +
            '<span style="display:inline-block; width:5px; height:5px; background:#ff4b28; border-radius:50%; margin-right:3px; vertical-align:middle;"></span><span style="color: #ff4b28;">[HOT]</span>' +
            '</span></div>';
  }

  if (legendEl.innerHTML !== html) {
    legendEl.innerHTML = html;
  }
};

window.FXEarthGlobe._getInstance = function(containerSelector) {
  var selector = containerSelector || '#hud-container';
  if (!window.FXEarthGlobe._instances[selector]) {
    var defaultSettings = {
      globeSpeed: 0.5,
      globeLights: true,
      globeMode: 'illustrative',
      globeLat: 55.6761,
      globeLng: 12.5683,
      globeBeacon: true,
      globeLayerClouds: false,
      globeLayerPrecipitation: false,
      globeLayerLightning: false,
      globeLayerVortex: false,
      globeLayerTemperature: false,
      globeSweepSpeed: 0.05,
      glassOpacity: 0.8,
      scale: 1.0,
      customTitle: undefined
    };
    
    // Initialize weather nodes
    var cloudFronts = [];
    for (var f = 0; f < 4; f++) {
      var front = {
        lat: -40 + Math.random() * 80,
        lng: -180 + Math.random() * 360,
        vLat: (Math.random() - 0.5) * 1.5,
        vLng: (Math.random() - 0.5) * 4.0 + 1.5,
        subNodes: []
      };
      var numSubNodes = 6 + Math.floor(Math.random() * 3); // 6-8 overlapping sub-nodes
      for (var k = 0; k < numSubNodes; k++) {
        front.subNodes.push({
          dLat: (Math.random() - 0.5) * 16,
          dLng: (Math.random() - 0.5) * 24,
          rFlat: 10 + Math.random() * 12,
          intensity: 0.4 + Math.random() * 0.6
        });
      }
      cloudFronts.push(front);
    }

    var cloudNodes = [];

    var precipNodes = [];
    for (var i = 0; i < 15; i++) {
      precipNodes.push({
        lat: -50 + Math.random() * 100,
        lng: -180 + Math.random() * 360,
        rFlat: 8 + Math.random() * 10,
        intensity: 0.3 + Math.random() * 0.7,
        vLat: (Math.random() - 0.5) * 3.0,
        vLng: (Math.random() - 0.5) * 8.0 + 3.0
      });
    }

    var tempNodes = [];
    for (var i = 0; i < 10; i++) {
      tempNodes.push({
        lat: -70 + Math.random() * 140,
        lng: -180 + Math.random() * 360,
        rFlat: 30 + Math.random() * 40,
        intensity: Math.random(),
        vLat: (Math.random() - 0.5) * 1.0,
        vLng: (Math.random() - 0.5) * 3.0
      });
    }

    window.FXEarthGlobe._instances[selector] = {
      containerSelector: selector,
      settings: defaultSettings,
      overlayElement: null,
      canvas: null,
      animationFrameId: null,
      rotationAngle: 0,
      sweepAngle: 0,
      lastFrameTime: null,
      landPoints: [],
      lat0Rad: 0,
      lng0Rad: 0,
      sinLat0: 0,
      cosLat0: 1,
      cloudFronts: cloudFronts,
      cloudNodes: cloudNodes,
      precipNodes: precipNodes,
      tempNodes: tempNodes,
      activeLightnings: [],
      activeVortices: [
        {
          lat: 15,
          lng: -40,
          vLat: 0.05,
          vLng: -0.15,
          k: 0.12,
          beta: 0.7,
          maxRadius: 28,
          angles: [0, 0, 0, 0, 0, 0]
        },
        {
          lat: 18,
          lng: 135,
          vLat: 0.04,
          vLng: -0.12,
          k: 0.14,
          beta: 0.65,
          maxRadius: 32,
          angles: [0, 0, 0, 0, 0, 0]
        }
      ],
      radarMetadata: null
    };
  }
  return window.FXEarthGlobe._instances[selector];
};

window.FXEarthGlobe._updateCache = function(containerSelector) {
  var instance = window.FXEarthGlobe._getInstance(containerSelector);
  if (!instance.settings) return;
  var lat = parseFloat(instance.settings.globeLat);
  var lng = parseFloat(instance.settings.globeLng);
  if (isNaN(lat)) lat = 55.6761;
  if (isNaN(lng)) lng = 12.5683;
  
  instance.lat0Rad = lat * Math.PI / 180;
  instance.lng0Rad = lng * Math.PI / 180;
  instance.sinLat0 = Math.sin(instance.lat0Rad);
  instance.cosLat0 = Math.cos(instance.lat0Rad);
};

